// 保留旧的水盾样式（可选择删除，但保留以防需要）
.eden-water-shield {
  position: absolute;
  // 定位到敌人立绘区域
  top: 40%; // 向上移动
  right: 3%;
  transform: translateY(-50%);
  pointer-events: none;
  z-index: 5; // 在立绘之后

  // 移动端尺寸 (匹配 avatar max-width: 180px)
  width: 200px;
  height: 300px;

  @media (min-width: 1024px) {
    // 桌面端尺寸 (匹配 avatar max-width: 320px)
    width: 350px;
    height: 530px;
    right: 5%;
  }

  .water-shield-overlay {
    position: absolute;
    inset: -15%; // 使用百分比覆盖，随父元素缩放
    background: linear-gradient(
      135deg,
      rgba(96, 165, 250, 0.3) 0%,
      rgba(59, 130, 246, 0.4) 25%,
      rgba(96, 165, 250, 0.2) 50%,
      rgba(59, 130, 246, 0.35) 75%,
      rgba(96, 165, 250, 0.3) 100%
    );
    border-radius: 50%;
    animation:
      waterShieldPulse 3s ease-in-out infinite,
      waterShieldRotate 8s linear infinite;
    box-shadow:
      0 0 30px rgba(96, 165, 250, 0.5),
      0 0 60px rgba(59, 130, 246, 0.3),
      inset 0 0 40px rgba(96, 165, 250, 0.2);
  }

  .sleep-icon {
    position: absolute;
    top: 5%;
    right: -15%;
    font-size: 24px; // 移动端
    animation: sleepFloat 2s ease-in-out infinite;

    @media (min-width: 1024px) {
      font-size: 36px; // 桌面端
    }
  }
}

@keyframes waterShieldPulse {
  0%,
  100% {
    opacity: 0.7;
    transform: scale(1);
  }
  50% {
    opacity: 1;
    transform: scale(1.05);
  }
}

@keyframes waterShieldRotate {
  from {
    filter: hue-rotate(0deg);
  }
  to {
    filter: hue-rotate(30deg);
  }
}

@keyframes sleepFloat {
  0%,
  100% {
    transform: translateY(0);
    opacity: 0.8;
  }
  50% {
    transform: translateY(-10px);
    opacity: 1;
  }
}

// ========== 伊登芙宁倒计时显示 (响应式缩放) ==========
.eden-countdown {
  position: absolute;
  // 移动端定位
  top: 60px;
  right: 1%;
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 10px;
  background: linear-gradient(135deg, rgba(30, 64, 175, 0.8), rgba(59, 130, 246, 0.6));
  border: 2px solid rgba(96, 165, 250, 0.6);
  border-radius: 16px;
  color: white;
  font-weight: bold;
  z-index: 25;
  animation: fadeIn 0.3s ease-out;
  box-shadow: 0 0 10px rgba(59, 130, 246, 0.4);

  @media (min-width: 1024px) {
    // 桌面端定位
    top: 80px;
    right: 3%;
    gap: 8px;
    padding: 8px 16px;
    border-radius: 20px;
    box-shadow: 0 0 15px rgba(59, 130, 246, 0.4);
  }

  .countdown-icon {
    font-size: 14px;

    @media (min-width: 1024px) {
      font-size: 20px;
    }
  }

  .countdown-number {
    font-size: 16px;
    font-family: 'Courier New', monospace;
    min-width: 20px;
    text-align: center;

    @media (min-width: 1024px) {
      font-size: 24px;
      min-width: 30px;
    }
  }

  &.countdown-urgent {
    background: linear-gradient(135deg, rgba(220, 38, 38, 0.8), rgba(239, 68, 68, 0.6));
    border-color: rgba(248, 113, 113, 0.6);
    animation: urgentPulse 0.5s ease-in-out infinite;
    box-shadow: 0 0 20px rgba(239, 68, 68, 0.5);
  }
}

@keyframes urgentPulse {
  0%,
  100% {
    transform: scale(1);
  }
  50% {
    transform: scale(1.1);
  }
}
