
.stats-panel {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.25em 0.5em;
  width: 100%;
  animation: fadeIn 0.3s ease;
  font-size: inherit; // 继承父级字体大小
}

.stats-compact {
  // 紧凑模式下缩小间距
  gap: 0.2em 0.3em;
}

.stat-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.4em;
  border-radius: 0.4em;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.05);
  min-width: 0; // 允许flex子项收缩

  .stats-compact & {
    padding: 0.2em;
    background: transparent;
    border: none;
  }
}

.stat-full {
  grid-column: span 2;
}

.stat-info {
  display: flex;
  align-items: center;
  gap: 0.3em;
  min-width: 0; // 允许收缩

  svg {
    flex-shrink: 0;
    width: 1em;
    height: 1em;
  }
}

.stat-label {
  font-size: 0.85em;
  font-weight: 500;
  text-transform: uppercase;
  color: #94a3b8;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;

  .stats-compact & {
    font-size: 0.75em;
  }
}

.stat-value {
  font-size: 1em;
  font-weight: 700;
  font-family: ui-monospace, monospace;
  color: white;
  flex-shrink: 0;

  .stats-compact & {
    font-size: 0.9em;
  }
}

.text-pink-400 {
  color: #f472b6;
}
.text-green-400 {
  color: #4ade80;
}
.text-cyan-400 {
  color: #22d3ee;
}
.text-orange-400 {
  color: #fb923c;
}
.text-rose-400 {
  color: #fb7185;
}
.text-yellow-400 {
  color: #facc15;
}
.text-purple-400 {
  color: #c084fc;
}

/* 状态效果样式 */
.status-section {
  grid-column: span 2;
  margin-top: 0.5em;
  display: flex;
  flex-direction: column;
  gap: 0.5em;
}

.status-divider {
  height: 1px;
  background: rgba(255, 255, 255, 0.1);
  width: 100%;
}

.status-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4em;
}

.status-item {
  display: flex;
  align-items: center;
  gap: 0.3em;
  padding: 0.2em 0.4em;
  border-radius: 0.3em;
  font-size: 0.8em;
  border: 1px solid transparent;

  &.status-buff {
    background: rgba(34, 197, 94, 0.1);
    color: #4ade80;
    border-color: rgba(34, 197, 94, 0.2);
  }

  &.status-debuff {
    background: rgba(244, 63, 94, 0.1);
    color: #fb7185;
    border-color: rgba(244, 63, 94, 0.2);
  }
}

.status-icon {
  font-weight: bold;
}

.status-duration {
  font-size: 0.9em;
  opacity: 0.8;
  margin-left: 0.2em;
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}
